import React from 'react';
import Section from './components/Section';
import './Section.css';

class Home extends React.Component{
    constructor(props) {
      super(props);
      this.state = {};
    }

    render() {
      return (<section className={this.state.headerInfoClass}>
                <div className={this.state.headerTitleInfoClass}>
                  <img src={this.state.domainLogo} alt="Domain Logo" className={this.state.headerTitleInfoDomainLogoClass}/>
                  <a href={this.state.domainURL} className={this.state.headerTitleInfoDomainUrlClass}>{this.state.pageName}</a>
                </div>
                <div className={this.state.headerMainInfoClass}>
                  <div className={this.state.headerMainInfoCurrentPageClass}>{this.state.currentPageName}</div>
                  <div className={this.state.headerMainInfoContactInfoClass}>
                    <div className={this.state.headerMainInfoContactLabelClass}>Contacts</div>
                    <div className={this.state.headerMainInfoTelegramInfoClass}>                      
                      <a href={this.state.telegramURL} target="_blank" rel="noopener noreferrer">
                        <img src={this.state.telegramLogo} alt="Telegram" className={this.state.headerMainInfoTelegramLogoClass}/>
                      </a>
                    </div>
                    <div className={this.state.headerMainInfoGmailInfoClass}>                      
                      <a href={this.state.gmailURL} target="_blank" rel="noopener noreferrer">
                        <img src={this.state.gmailLogo} alt="Gmail" className={this.state.headerMainInfoGmailLogoClass}/>
                      </a>
                    </div>
                    <div className={this.state.headerMainInfoGitHubInfoClass}>                      
                      <a href={this.state.githubURL} className={this.state.headerMainInfoGitHubUrlClass}>
                        <img src={this.state.githubLogo} alt="GitHub Logo" className={this.state.headerMainInfoGitHubLogoClass}/>
                      </a>
                    </div>
                  </div>

                </div>
              </section>
      );
    }
  }


<Section id="versioning" title="Versioning" content="Installation Guides, User Guides, Developer Guides, Administration Guides, Manuals, Books, Examples, External Material, Projects" />


export default Home;
